import React, { useEffect, useRef } from 'react';

function ChatWindow({ messages, input, setInput, onSend, theme, sidebarOpen, onOpenMobileSidebar }) {
    const bottomRef = useRef();
    useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

    return (
        <div className="flex-1 flex flex-col bg-white/40 backdrop-blur-sm relative">
            {/* 消息列表 */}
            <div className="flex-1 overflow-y-auto px-4 md:px-6 py-4 space-y-4">
                {messages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] md:max-w-[78%] px-4 py-3 rounded-3xl transition-all duration-300 ${msg.sender === 'user' ? theme.userBubble + ' rounded-br-lg' : theme.aiBubble + ' rounded-bl-lg'
                            }`}>
                            <p className="text-[15px] leading-relaxed whitespace-pre-wrap">{msg.text}</p>
                        </div>
                    </div>
                ))}
                <div ref={bottomRef} />
            </div>

            {/* 输入区 */}
            <div className="p-3 md:p-4 bg-white/70 backdrop-blur-md border-t border-gray-200/50">
                <div className="flex gap-2 max-w-3xl mx-auto">
                    <textarea
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); onSend(); } }}
                        rows={1}
                        className={`flex-1 resize-none rounded-2xl border ${theme.input} bg-white/80 px-4 py-3 text-sm focus:outline-none focus:ring-2 transition`}
                        placeholder="✨ 问小智老师问题..."
                    />
                    <button onClick={onSend} className={`px-5 rounded-2xl font-semibold text-sm ${theme.sendBtn} transition-all hover:scale-105`}>
                        发送 ↑
                    </button>
                </div>
                <p className="text-[10px] text-gray-400 mt-1 ml-2">回车发送 · Shift+回车换行</p>
            </div>

            {/* 移动端浮动工具箱按钮 */}
            <button
                onClick={onOpenMobileSidebar}
                className={`md:hidden fixed bottom-24 right-4 w-12 h-12 rounded-full ${theme.sidebar} shadow-lg flex items-center justify-center text-xl hover:scale-110 transition z-40`}
            >
                🧰
            </button>
        </div>
    );
}

export default ChatWindow;
